/**
 * ECharts 核心库适配层（简化版）
 * @description 为微信小程序提供 ECharts 兼容接口
 * @version 1.0.0
 * @author 记账小程序团队
 * 
 * ⚠️ 注意：这是一个简化版适配层，实际项目中请从 ECharts 官网下载定制版
 * 下载地址：https://echarts.apache.org/zh/builder.html
 * 选择组件：折线图、提示框、图例、数据缩放
 */

(function(global) {
  'use strict';

  /**
   * ECharts 主对象
   */
  const echarts = {
    // 版本号
    version: '1.0.0-simplified',
    
    // 图表实例存储
    instances: [],
    
    /**
     * 初始化图表
     * @param {Object} canvas - Canvas 节点
     * @param {string} theme - 主题（暂不支持）
     * @param {Object} opts - 配置选项
     * @returns {Object} 图表实例
     */
    init: function(canvas, theme, opts) {
      // 创建新的图表实例
      const instance = new EChartsInstance(canvas, opts);
      // 存储实例
      this.instances.push(instance);
      // 返回实例
      return instance;
    },
    
    /**
     * 销毁图表实例
     * @param {Object} instance - 图表实例
     */
    dispose: function(instance) {
      // 查找实例索引
      const index = this.instances.indexOf(instance);
      // 如果找到则移除
      if (index > -1) {
        this.instances.splice(index, 1);
      }
      // 调用实例的销毁方法
      if (instance && instance.dispose) {
        instance.dispose();
      }
    }
  };

  /**
   * ECharts 图表实例类
   * @class EChartsInstance
   */
  class EChartsInstance {
    /**
     * 构造函数
     * @param {Object} canvas - Canvas 节点
     * @param {Object} opts - 配置选项
     */
    constructor(canvas, opts) {
      // Canvas 节点
      this._canvas = canvas;
      // Canvas 2D 上下文
      this._ctx = canvas.getContext('2d');
      // 宽度
      this._width = opts.width || 300;
      // 高度
      this._height = opts.height || 200;
      // 设备像素比
      this._dpr = opts.devicePixelRatio || 1;
      // 图表配置
      this._option = null;
      // 事件监听器
      this._listeners = {};
      // ZRender 实例（模拟）
      this._zr = {
        handler: {
          dispatch: this._dispatchEvent.bind(this)
        }
      };
      // Tooltip 相关属性
      this._tooltipVisible = false; // tooltip 是否可见
      this._tooltipX = 0; // tooltip X 坐标
      this._tooltipY = 0; // tooltip Y 坐标
      this._tooltipDataIndex = -1; // 当前 tooltip 显示的数据索引
      this._tooltipHideTimer = null; // tooltip 隐藏定时器
      
      // 动画相关属性
      this._animationProgress = 1; // 动画进度（0-1）
      this._animationFrameId = null; // 动画帧 ID
      this._animationDuration = 800; // 动画持续时间（毫秒）
      this._animationStartTime = 0; // 动画开始时间
      this._isAnimating = false; // 是否正在动画中
    }

    /**
     * 设置图表配置
     * @param {Object} option - ECharts 配置对象
     * @param {boolean} notMerge - 是否不合并配置
     */
    setOption(option, notMerge) {
      // 存储配置
      if (notMerge) {
        this._option = option;
      } else {
        // 合并配置
        this._option = this._mergeOption(this._option, option);
      }
      
      // 启动入场动画
      this._startAnimation();
    }

    /**
     * 合并配置对象
     * @param {Object} target - 目标配置
     * @param {Object} source - 源配置
     * @returns {Object} 合并后的配置
     */
    _mergeOption(target, source) {
      // 如果目标为空，直接返回源
      if (!target) return source;
      // 如果源为空，直接返回目标
      if (!source) return target;
      // 创建合并结果
      const result = Object.assign({}, target);
      // 遍历源的属性
      for (const key in source) {
        if (source.hasOwnProperty(key)) {
          // 如果是数组，直接替换
          if (Array.isArray(source[key])) {
            result[key] = source[key];
          }
          // 如果是对象，递归合并
          else if (typeof source[key] === 'object' && source[key] !== null) {
            result[key] = this._mergeOption(result[key], source[key]);
          }
          // 其他类型，直接赋值
          else {
            result[key] = source[key];
          }
        }
      }
      return result;
    }

    /**
     * 渲染图表
     * @param {number} progress - 动画进度（0-1），默认为1（无动画）
     */
    _render(progress = 1) {
      // 检查 Canvas 上下文是否存在（防止销毁后调用）
      if (!this._ctx) return;
      // 清除画布
      this._clearCanvas();
      // 检查配置是否存在
      if (!this._option) return;
      
      // 判断图表类型
      const series = this._option.series || [];
      const chartType = series[0]?.type || 'line';
      
      // 根据图表类型选择不同的渲染流程
      if (chartType === 'pie') {
        // 饼图渲染流程
        // 绘制饼图，传入动画进度
        this._drawPie(progress);
        // 绘制饼图图例
        this._drawPieLegend();
      } else {
        // 折线图渲染流程
        // 绘制网格线
        this._drawGrid();
        // 绘制 X 轴
        this._drawXAxis();
        // 绘制 Y 轴
        this._drawYAxis();
        // 绘制系列（折线），传入动画进度
        this._drawSeries(progress);
        // 绘制图例
        this._drawLegend();
      }
      
      // 绘制 tooltip（如果可见）
      if (this._tooltipVisible) {
        this._drawTooltip();
      }
    }

    /**
     * 清除画布
     */
    _clearCanvas() {
      // 检查 Canvas 上下文是否存在（防止销毁后调用）
      if (!this._ctx) return;
      // 设置清除区域
      this._ctx.clearRect(0, 0, this._width * this._dpr, this._height * this._dpr);
    }

    /**
     * 绘制网格线
     */
    _drawGrid() {
      // 获取网格配置
      const grid = this._option.grid || {};
      // 网格左边距
      const left = this._parsePercent(grid.left || '3%', this._width);
      // 网格右边距
      const right = this._parsePercent(grid.right || '4%', this._width);
      // 网格上边距
      const top = this._parsePercent(grid.top || '10%', this._height);
      // 网格下边距
      const bottom = this._parsePercent(grid.bottom || '3%', this._height);
      
      // 计算网格区域
      this._gridRect = {
        x: left * this._dpr,
        y: top * this._dpr,
        width: (this._width - left - right) * this._dpr,
        height: (this._height - top - bottom) * this._dpr
      };
      
      // 检查是否显示网格
      if (this._option.yAxis && this._option.yAxis.splitLine !== false) {
        // 设置网格线样式
        this._ctx.strokeStyle = '#E5E5E5';
        this._ctx.lineWidth = 1;
        
        // 绘制水平网格线（5条）
        const gridHeight = this._gridRect.height;
        const gridTop = this._gridRect.y;
        const gridLeft = this._gridRect.x;
        const gridWidth = this._gridRect.width;
        
        for (let i = 0; i <= 5; i++) {
          const y = gridTop + (gridHeight / 5) * i;
          // 开始绘制路径
          this._ctx.beginPath();
          // 移动到起点
          this._ctx.moveTo(gridLeft, y);
          // 绘制到终点
          this._ctx.lineTo(gridLeft + gridWidth, y);
          // 描边
          this._ctx.stroke();
        }
      }
    }

    /**
     * 绘制 X 轴
     */
    _drawXAxis() {
      // 获取 X 轴配置
      const xAxis = this._option.xAxis;
      // 检查配置是否存在
      if (!xAxis) return;
      
      // 获取数据
      const data = xAxis.data || [];
      // 计算每个数据点的宽度
      const pointWidth = this._gridRect.width / Math.max(data.length - 1, 1);
      
      // 存储 X 轴点位置
      this._xPoints = [];
      
      // 设置文字样式
      this._ctx.font = `${12 * this._dpr}px sans-serif`;
      this._ctx.fillStyle = '#666666';
      this._ctx.textAlign = 'center';
      this._ctx.textBaseline = 'top';
      
      // 绘制 X 轴标签
      data.forEach((label, index) => {
        // 计算标签 X 坐标
        const x = this._gridRect.x + pointWidth * index;
        // 计算标签 Y 坐标
        const y = this._gridRect.y + this._gridRect.height + 5 * this._dpr;
        // 存储点位置
        this._xPoints.push(x);
        // 绘制标签文字
        this._ctx.fillText(label, x, y);
      });
    }

    /**
     * 绘制 Y 轴
     */
    _drawYAxis() {
      // 获取 Y 轴配置
      const yAxis = this._option.yAxis;
      // 检查配置是否存在
      if (!yAxis) return;
      
      // 计算最大值（从系列数据中）
      let maxValue = 0;
      if (this._option.series) {
        this._option.series.forEach(s => {
          if (s.data) {
            maxValue = Math.max(maxValue, ...s.data);
          }
        });
      }
      // 向上取整到合适的刻度
      maxValue = this._ceilToNice(maxValue);
      
      // 存储最大值
      this._yMax = maxValue;
      
      // 设置文字样式
      this._ctx.font = `${12 * this._dpr}px sans-serif`;
      this._ctx.fillStyle = '#999999';
      this._ctx.textAlign = 'right';
      this._ctx.textBaseline = 'middle';
      
      // 绘制 Y 轴标签（5个刻度）
      for (let i = 0; i <= 5; i++) {
        // 计算标签值
        const value = Math.round(maxValue * (5 - i) / 5);
        // 格式化金额显示
        const label = this._formatMoney(value);
        // 计算 Y 坐标
        const y = this._gridRect.y + (this._gridRect.height / 5) * i;
        // 计算 X 坐标
        const x = this._gridRect.x - 5 * this._dpr;
        // 绘制标签文字
        this._ctx.fillText(label, x, y);
      }
    }

    /**
     * 绘制系列（折线）
     * @param {number} progress - 动画进度（0-1），默认为1（无动画）
     */
    _drawSeries(progress = 1) {
      // 获取系列配置
      const series = this._option.series;
      // 检查配置是否存在
      if (!series || series.length === 0) return;
      
      // 使用缓动函数处理进度（让动画更自然）
      const easedProgress = this._easeOutCubic(progress);
      
      // 遍历每个系列
      series.forEach((s, seriesIndex) => {
        // 只处理折线图
        if (s.type !== 'line') return;
        
        // 获取数据
        const data = s.data || [];
        // 检查数据是否为空
        if (data.length === 0) return;
        
        // 获取样式配置
        const lineStyle = s.lineStyle || {};
        const itemStyle = s.itemStyle || {};
        const areaStyle = s.areaStyle;
        
        // 获取颜色
        const color = itemStyle.color || lineStyle.color || (seriesIndex === 0 ? '#07C160' : '#FA5151');
        
        // 计算点位置
        const points = [];
        data.forEach((value, index) => {
          // 检查 X 轴点是否存在
          if (!this._xPoints || !this._xPoints[index]) return;
          // 计算 X 坐标
          const x = this._xPoints[index];
          // 计算 Y 坐标（考虑最大值）
          const y = this._gridRect.y + this._gridRect.height - (value / this._yMax) * this._gridRect.height;
          // 存储点位置
          points.push({ x, y, value });
        });
        
        // 根据动画进度计算可见点数
        const visibleCount = Math.max(1, Math.floor(points.length * easedProgress));
        // 计算部分显示的进度（用于插值最后一个点）
        const partialProgress = (points.length * easedProgress) - Math.floor(points.length * easedProgress);
        
        // 获取可见的点（用于动画）
        const visiblePoints = points.slice(0, visibleCount);
        
        // 如果有部分进度，添加插值点
        if (visibleCount < points.length && partialProgress > 0 && visiblePoints.length > 0) {
          const lastVisible = visiblePoints[visiblePoints.length - 1];
          const nextPoint = points[visibleCount];
          if (nextPoint) {
            // 插值计算中间点位置
            const interpolatedPoint = {
              x: lastVisible.x + (nextPoint.x - lastVisible.x) * partialProgress,
              y: lastVisible.y + (nextPoint.y - lastVisible.y) * partialProgress,
              value: lastVisible.value,
              isInterpolated: true // 标记为插值点，不绘制数据点圆圈
            };
            visiblePoints.push(interpolatedPoint);
          }
        }
        
        // 绘制渐变填充区域
        if (areaStyle && visiblePoints.length > 1) {
          // 创建线性渐变
          const gradient = this._ctx.createLinearGradient(0, this._gridRect.y, 0, this._gridRect.y + this._gridRect.height);
          // 设置渐变颜色
          if (typeof areaStyle.color === 'object' && areaStyle.color.colorStops) {
            // 使用配置的渐变
            areaStyle.color.colorStops.forEach(stop => {
              gradient.addColorStop(stop.offset, stop.color);
            });
          } else {
            // 使用默认渐变
            gradient.addColorStop(0, this._hexToRgba(color, 0.3));
            gradient.addColorStop(1, this._hexToRgba(color, 0.05));
          }
          
          // 绘制填充区域
          this._ctx.beginPath();
          // 移动到第一个点
          this._ctx.moveTo(visiblePoints[0].x, visiblePoints[0].y);
          // 连接所有可见点
          for (let i = 1; i < visiblePoints.length; i++) {
            this._ctx.lineTo(visiblePoints[i].x, visiblePoints[i].y);
          }
          // 连接到右下角
          this._ctx.lineTo(visiblePoints[visiblePoints.length - 1].x, this._gridRect.y + this._gridRect.height);
          // 连接到左下角
          this._ctx.lineTo(visiblePoints[0].x, this._gridRect.y + this._gridRect.height);
          // 闭合路径
          this._ctx.closePath();
          // 填充渐变
          this._ctx.fillStyle = gradient;
          this._ctx.fill();
        }
        
        // 绘制折线
        this._ctx.beginPath();
        this._ctx.strokeStyle = color;
        this._ctx.lineWidth = (lineStyle.width || 2) * this._dpr;
        this._ctx.lineJoin = 'round';
        this._ctx.lineCap = 'round';
        
        // 连接可见点
        visiblePoints.forEach((point, index) => {
          if (index === 0) {
            // 移动到第一个点
            this._ctx.moveTo(point.x, point.y);
          } else {
            // 绘制平滑曲线
            const prevPoint = visiblePoints[index - 1];
            const cpX = (prevPoint.x + point.x) / 2;
            // 二次贝塞尔曲线
            this._ctx.quadraticCurveTo(cpX, prevPoint.y, cpX, (prevPoint.y + point.y) / 2);
            this._ctx.quadraticCurveTo(cpX, point.y, point.x, point.y);
          }
        });
        // 描边
        this._ctx.stroke();
        
        // 绘制数据点（不包括插值点）
        visiblePoints.forEach(point => {
          // 插值点不绘制数据点圆圈
          if (point.isInterpolated) return;
          // 绘制外圈
          this._ctx.beginPath();
          this._ctx.arc(point.x, point.y, (s.symbolSize || 8) * this._dpr / 2, 0, Math.PI * 2);
          this._ctx.fillStyle = '#ffffff';
          this._ctx.fill();
          this._ctx.strokeStyle = color;
          this._ctx.lineWidth = 2 * this._dpr;
          this._ctx.stroke();
          
          // 绘制内圈
          this._ctx.beginPath();
          this._ctx.arc(point.x, point.y, ((s.symbolSize || 8) - 4) * this._dpr / 2, 0, Math.PI * 2);
          this._ctx.fillStyle = color;
          this._ctx.fill();
        });
        
        // 存储点数据用于交互
        if (seriesIndex === 0) {
          this._incomePoints = points;
        } else {
          this._expensePoints = points;
        }
      });
    }

    /**
     * 绘制图例
     */
    _drawLegend() {
      // 获取图例配置
      const legend = this._option.legend;
      // 检查是否显示图例
      if (!legend || !legend.show === false) return;
      
      // 获取图例数据
      const data = legend.data || [];
      // 检查数据是否为空
      if (data.length === 0) return;
      
      // 设置图例位置（底部居中）
      const legendY = this._height * this._dpr - 20 * this._dpr;
      const legendSpacing = 80 * this._dpr;
      const startX = (this._width * this._dpr - (data.length - 1) * legendSpacing) / 2;
      
      // 设置文字样式
      this._ctx.font = `${12 * this._dpr}px sans-serif`;
      this._ctx.textAlign = 'left';
      this._ctx.textBaseline = 'middle';
      
      // 绘制每个图例项
      data.forEach((name, index) => {
        // 计算 X 坐标
        const x = startX + index * legendSpacing;
        // 获取对应颜色
        const color = index === 0 ? '#07C160' : '#FA5151';
        
        // 绘制圆点
        this._ctx.beginPath();
        this._ctx.arc(x, legendY, 6 * this._dpr, 0, Math.PI * 2);
        this._ctx.fillStyle = color;
        this._ctx.fill();
        
        // 绘制文字
        this._ctx.fillStyle = '#666666';
        this._ctx.fillText(name, x + 12 * this._dpr, legendY);
      });
    }

    /**
     * 格式化金额
     * @param {number} value - 金额值（单位：分）
     * @returns {string} 格式化后的金额字符串
     */
    _formatMoney(value) {
      // 转换为元
      const yuan = value / 100;
      // 根据金额大小选择格式
      if (yuan >= 10000) {
        return (yuan / 10000).toFixed(1) + '万';
      } else if (yuan >= 1000) {
        return (yuan / 1000).toFixed(1) + 'k';
      } else {
        return yuan.toFixed(0);
      }
    }

    /**
     * 将百分比字符串转换为数值
     * @param {string|number} value - 百分比字符串或数值
     * @param {number} base - 基准值
     * @returns {number} 转换后的数值
     */
    _parsePercent(value, base) {
      // 如果已经是数值，直接返回
      if (typeof value === 'number') return value;
      // 如果是字符串且以 % 结尾
      if (typeof value === 'string' && value.endsWith('%')) {
        return (parseFloat(value) / 100) * base;
      }
      // 默认返回 0
      return 0;
    }

    /**
     * 向上取整到合适的刻度值
     * @param {number} value - 原始值
     * @returns {number} 取整后的值
     */
    _ceilToNice(value) {
      // 如果值为 0，返回默认值
      if (value === 0) return 100000; // 默认 1000 元
      // 计算数量级
      const magnitude = Math.pow(10, Math.floor(Math.log10(value)));
      // 计算有效数字
      const normalized = value / magnitude;
      // 向上取整到 1, 2, 5 的倍数
      let nice;
      if (normalized <= 1) nice = 1;
      else if (normalized <= 2) nice = 2;
      else if (normalized <= 5) nice = 5;
      else nice = 10;
      // 返回取整后的值
      return nice * magnitude;
    }

    /**
     * 将十六进制颜色转换为 RGBA
     * @param {string} hex - 十六进制颜色值
     * @param {number} alpha - 透明度
     * @returns {string} RGBA 颜色字符串
     */
    _hexToRgba(hex, alpha) {
      // 移除 # 号
      hex = hex.replace('#', '');
      // 解析 RGB 值
      const r = parseInt(hex.substring(0, 2), 16);
      const g = parseInt(hex.substring(2, 4), 16);
      const b = parseInt(hex.substring(4, 6), 16);
      // 返回 RGBA 字符串
      return `rgba(${r}, ${g}, ${b}, ${alpha})`;
    }

    /**
     * 绑定事件
     * @param {string} eventName - 事件名称
     * @param {Function} handler - 事件处理函数
     */
    on(eventName, handler) {
      // 存储事件监听器
      if (!this._listeners[eventName]) {
        this._listeners[eventName] = [];
      }
      this._listeners[eventName].push(handler);
    }

    /**
     * 解绑事件
     * @param {string} eventName - 事件名称
     * @param {Function} handler - 事件处理函数
     */
    off(eventName, handler) {
      // 检查事件是否存在
      if (!this._listeners[eventName]) return;
      // 移除指定的监听器
      if (handler) {
        const index = this._listeners[eventName].indexOf(handler);
        if (index > -1) {
          this._listeners[eventName].splice(index, 1);
        }
      } else {
        // 移除所有监听器
        this._listeners[eventName] = [];
      }
    }

    /**
     * 触发事件
     * @param {string} eventName - 事件名称
     * @param {Object} params - 事件参数
     */
    _trigger(eventName, params) {
      // 检查事件是否存在
      if (!this._listeners[eventName]) return;
      // 调用所有监听器
      this._listeners[eventName].forEach(handler => {
        handler(params);
      });
    }

    /**
     * 分发事件（用于触摸事件）
     * @param {string} type - 事件类型
     * @param {Object} e - 事件对象
     */
    _dispatchEvent(type, e) {
      // 根据事件类型触发对应的处理
      if (type === 'mousedown' || type === 'mousemove' || type === 'mouseup') {
        this._handleTouchEvent(type, e);
      }
    }

    /**
     * 处理触摸事件
     * @param {string} type - 事件类型
     * @param {Object} e - 事件对象
     */
    _handleTouchEvent(type, e) {
      // 获取触摸点位置（注意：touchend 时 e.touches 是空数组，需要检查数组长度）
      let touch = null;
      // 优先从 touches 获取（touchstart/touchmove 时有数据）
      if (e.touches && e.touches.length > 0) {
        touch = e.touches[0];
      }
      // touchend 时 touches 为空，需要从 changedTouches 获取
      else if (e.changedTouches && e.changedTouches.length > 0) {
        touch = e.changedTouches[0];
      }
      // 如果没有有效的触摸点，直接返回
      if (!touch) return;
      
      // 计算相对于 Canvas 的坐标
      const x = touch.x * this._dpr;
      const y = touch.y * this._dpr;
      
      // 处理触摸移动（拖拽查看）
      if (type === 'mousemove' || type === 'touchmove') {
        // 检查是否在图表区域内
        if (this._gridRect && 
            x >= this._gridRect.x && 
            x <= this._gridRect.x + this._gridRect.width &&
            y >= this._gridRect.y && 
            y <= this._gridRect.y + this._gridRect.height) {
          // 查找最近的数据点索引
          const dataIndex = this._findNearestDataIndex(x);
          if (dataIndex !== -1 && dataIndex !== this._tooltipDataIndex) {
            // 显示 tooltip
            this._showTooltip(dataIndex, x, y);
          }
        } else {
          // 隐藏 tooltip
          this._hideTooltip();
        }
      }
      
      // 处理触摸结束
      if (type === 'mouseup' || type === 'touchend') {
        // 检查是否点击了数据点
        this._checkDataPointClick(x, y);
        // 清除之前的隐藏定时器
        if (this._tooltipHideTimer) {
          clearTimeout(this._tooltipHideTimer);
          this._tooltipHideTimer = null;
        }
        // 延迟隐藏 tooltip（给用户时间查看）
        this._tooltipHideTimer = setTimeout(() => {
          this._hideTooltip();
          this._tooltipHideTimer = null;
        }, 2000);
      }
    }

    /**
     * 查找最近的数据点索引
     * @param {number} x - X 坐标
     * @returns {number} 数据点索引，-1 表示未找到
     */
    _findNearestDataIndex(x) {
      // 检查 X 轴点是否存在
      if (!this._xPoints || this._xPoints.length === 0) return -1;
      
      // 查找最近的点
      let minDistance = Infinity;
      let nearestIndex = -1;
      
      this._xPoints.forEach((pointX, index) => {
        const distance = Math.abs(x - pointX);
        if (distance < minDistance) {
          minDistance = distance;
          nearestIndex = index;
        }
      });
      
      // 如果距离太远，返回 -1
      if (minDistance > 50 * this._dpr) return -1;
      
      return nearestIndex;
    }

    /**
     * 显示 tooltip
     * @param {number} dataIndex - 数据索引
     * @param {number} x - X 坐标
     * @param {number} y - Y 坐标
     */
    _showTooltip(dataIndex, x, y) {
      // 检查配置是否存在
      if (!this._option || !this._option.tooltip) return;
      
      // 更新 tooltip 状态
      this._tooltipVisible = true;
      this._tooltipDataIndex = dataIndex;
      this._tooltipX = x / this._dpr;
      this._tooltipY = y / this._dpr;
      
      // 重新渲染（显示 tooltip）
      this._render();
    }

    /**
     * 隐藏 tooltip
     */
    _hideTooltip() {
      // 更新 tooltip 状态
      this._tooltipVisible = false;
      this._tooltipDataIndex = -1;
      
      // 重新渲染（隐藏 tooltip）
      this._render();
    }

    /**
     * 绘制 tooltip
     */
    _drawTooltip() {
      // 检查数据索引是否有效
      if (this._tooltipDataIndex < 0) return;
      
      // 获取配置
      const tooltip = this._option.tooltip || {};
      const series = this._option.series || [];
      const xAxis = this._option.xAxis || {};
      
      // 获取日期标签
      const dateLabel = (xAxis.data || [])[this._tooltipDataIndex] || '';
      
      // 获取收入和支出数据
      const incomeValue = (series[0]?.data || [])[this._tooltipDataIndex] || 0;
      const expenseValue = (series[1]?.data || [])[this._tooltipDataIndex] || 0;
      
      // 格式化金额（分转元）
      const formatMoney = (value) => {
        return (value / 100).toFixed(2);
      };
      
      // 构建 tooltip 文本
      const lines = [
        dateLabel,
        `收入：¥${formatMoney(incomeValue)}`,
        `支出：¥${formatMoney(expenseValue)}`
      ];
      
      // 计算 tooltip 尺寸
      const padding = 10 * this._dpr;
      const lineHeight = 18 * this._dpr;
      const fontSize = 12 * this._dpr;
      
      this._ctx.font = `${fontSize}px sans-serif`;
      const maxWidth = Math.max(...lines.map(line => this._ctx.measureText(line).width));
      const tooltipWidth = maxWidth + padding * 2;
      const tooltipHeight = lines.length * lineHeight + padding * 2;
      
      // 计算 tooltip 位置（跟随触摸点，但不超出画布）
      let tooltipX = this._tooltipX * this._dpr;
      let tooltipY = this._tooltipY * this._dpr - tooltipHeight - 10 * this._dpr;
      
      // 确保 tooltip 不超出画布右边界
      if (tooltipX + tooltipWidth > this._width * this._dpr) {
        tooltipX = this._width * this._dpr - tooltipWidth - 10 * this._dpr;
      }
      // 确保 tooltip 不超出画布左边界
      if (tooltipX < 0) {
        tooltipX = 10 * this._dpr;
      }
      // 确保 tooltip 不超出画布上边界
      if (tooltipY < 0) {
        tooltipY = this._tooltipY * this._dpr + 20 * this._dpr;
      }
      
      // 绘制 tooltip 背景
      this._ctx.fillStyle = 'rgba(255, 255, 255, 0.95)';
      this._ctx.strokeStyle = '#e0e0e0';
      this._ctx.lineWidth = 1;
      
      // 绘制圆角矩形
      const radius = 4 * this._dpr;
      this._ctx.beginPath();
      this._ctx.moveTo(tooltipX + radius, tooltipY);
      this._ctx.lineTo(tooltipX + tooltipWidth - radius, tooltipY);
      this._ctx.arcTo(tooltipX + tooltipWidth, tooltipY, tooltipX + tooltipWidth, tooltipY + radius, radius);
      this._ctx.lineTo(tooltipX + tooltipWidth, tooltipY + tooltipHeight - radius);
      this._ctx.arcTo(tooltipX + tooltipWidth, tooltipY + tooltipHeight, tooltipX + tooltipWidth - radius, tooltipY + tooltipHeight, radius);
      this._ctx.lineTo(tooltipX + radius, tooltipY + tooltipHeight);
      this._ctx.arcTo(tooltipX, tooltipY + tooltipHeight, tooltipX, tooltipY + tooltipHeight - radius, radius);
      this._ctx.lineTo(tooltipX, tooltipY + radius);
      this._ctx.arcTo(tooltipX, tooltipY, tooltipX + radius, tooltipY, radius);
      this._ctx.closePath();
      this._ctx.fill();
      this._ctx.stroke();
      
      // 绘制文本
      this._ctx.fillStyle = '#333333';
      this._ctx.font = `bold ${fontSize}px sans-serif`;
      this._ctx.textAlign = 'left';
      this._ctx.textBaseline = 'top';
      this._ctx.fillText(lines[0], tooltipX + padding, tooltipY + padding);
      
      this._ctx.font = `${fontSize}px sans-serif`;
      // 绘制收入（绿色）
      this._ctx.fillStyle = '#07c160';
      this._ctx.fillText(lines[1], tooltipX + padding, tooltipY + padding + lineHeight);
      
      // 绘制支出（红色）
      this._ctx.fillStyle = '#fa5151';
      this._ctx.fillText(lines[2], tooltipX + padding, tooltipY + padding + lineHeight * 2);
    }

    /**
     * 检查数据点点击
     * @param {number} x - X 坐标
     * @param {number} y - Y 坐标
     */
    _checkDataPointClick(x, y) {
      // 检查收入数据点
      if (this._incomePoints) {
        this._incomePoints.forEach((point, index) => {
          const distance = Math.sqrt(Math.pow(x - point.x, 2) + Math.pow(y - point.y, 2));
          if (distance < 20 * this._dpr) {
            // 触发点击事件
            this._trigger('click', {
              componentType: 'series',
              seriesType: 'line',
              seriesIndex: 0,
              dataIndex: index,
              data: point.value,
              name: '收入'
            });
          }
        });
      }
      
      // 检查支出数据点
      if (this._expensePoints) {
        this._expensePoints.forEach((point, index) => {
          const distance = Math.sqrt(Math.pow(x - point.x, 2) + Math.pow(y - point.y, 2));
          if (distance < 20 * this._dpr) {
            // 触发点击事件
            this._trigger('click', {
              componentType: 'series',
              seriesType: 'line',
              seriesIndex: 1,
              dataIndex: index,
              data: point.value,
              name: '支出'
            });
          }
        });
      }
    }

    /**
     * 获取 ZRender 实例
     * @returns {Object} ZRender 实例
     */
    getZr() {
      return this._zr;
    }

    /**
     * 调整图表尺寸
     * @param {Object} opts - 尺寸配置
     */
    resize(opts) {
      // 更新宽高
      if (opts.width) this._width = opts.width;
      if (opts.height) this._height = opts.height;
      // 重新渲染（使用当前动画进度）
      this._render(this._animationProgress);
    }

    /**
     * 销毁实例
     */
    dispose() {
      // 取消正在进行的动画（微信小程序使用 clearTimeout）
      if (this._animationFrameId) {
        clearTimeout(this._animationFrameId);
        this._animationFrameId = null;
      }
      // 取消 tooltip 隐藏定时器
      if (this._tooltipHideTimer) {
        clearTimeout(this._tooltipHideTimer);
        this._tooltipHideTimer = null;
      }
      // 清除画布
      this._clearCanvas();
      // 清除引用
      this._canvas = null;
      this._ctx = null;
      this._option = null;
      this._listeners = {};
    }
    
    /**
     * 启动入场动画
     */
    _startAnimation() {
      // 取消之前的动画（微信小程序使用 clearTimeout）
      if (this._animationFrameId) {
        clearTimeout(this._animationFrameId);
        this._animationFrameId = null;
      }
      
      // 重置动画状态
      this._animationProgress = 0;
      this._animationStartTime = Date.now();
      this._isAnimating = true;
      
      // 开始动画帧循环
      this._animateFrame();
    }
    
    /**
     * 动画帧更新
     * 使用 setTimeout 替代 requestAnimationFrame（微信小程序兼容）
     */
    _animateFrame() {
      // 计算已经过的时间
      const elapsed = Date.now() - this._animationStartTime;
      // 计算进度（0-1）
      this._animationProgress = Math.min(elapsed / this._animationDuration, 1);
      
      // 渲染当前帧
      this._render(this._animationProgress);
      
      // 如果动画未完成，继续下一帧
      if (this._animationProgress < 1) {
        // 使用 setTimeout 替代 requestAnimationFrame（微信小程序兼容）
        // 16ms 约等于 60fps
        this._animationFrameId = setTimeout(() => {
          this._animateFrame();
        }, 16);
      } else {
        // 动画完成
        this._isAnimating = false;
        this._animationFrameId = null;
      }
    }
    
    /**
     * 绘制饼图
     * @param {number} progress - 动画进度（0-1）
     */
    _drawPie(progress = 1) {
      // 获取系列配置
      const series = this._option.series;
      // 检查配置是否存在
      if (!series || series.length === 0) return;
      
      // 获取第一个饼图系列
      const pieSeries = series.find(s => s.type === 'pie');
      if (!pieSeries) return;
      
      // 获取数据
      const data = pieSeries.data || [];
      // 检查数据是否为空
      if (data.length === 0) return;
      
      // 使用缓动函数处理进度
      const easedProgress = this._easeOutCubic(progress);
      
      // 计算饼图中心位置和半径
      const center = pieSeries.center || ['50%', '50%'];
      const radius = pieSeries.radius || ['0%', '40%'];
      
      // 解析中心坐标
      const centerX = this._parsePercent(center[0], this._width) * this._dpr;
      const centerY = this._parsePercent(center[1], this._height) * this._dpr;
      
      // 解析半径（支持环形图：[内半径, 外半径]）
      let innerRadius = 0;
      let outerRadius = 0;
      if (Array.isArray(radius)) {
        innerRadius = this._parsePercent(radius[0], Math.min(this._width, this._height)) * this._dpr;
        outerRadius = this._parsePercent(radius[1], Math.min(this._width, this._height)) * this._dpr;
      } else {
        outerRadius = this._parsePercent(radius, Math.min(this._width, this._height)) * this._dpr;
      }
      
      // 存储饼图数据用于交互
      this._pieData = [];
      
      // 计算总和
      const total = data.reduce((sum, item) => sum + (item.value || 0), 0);
      if (total === 0) return;
      
      // 默认颜色数组
      const defaultColors = ['#5470c6', '#91cc75', '#fac858', '#ee6666', '#73c0de', '#3ba272', '#fc8452', '#9a60b4', '#ea7ccc'];
      
      // 绘制饼图扇形
      let startAngle = (pieSeries.startAngle || 90) * Math.PI / 180 - Math.PI / 2; // 转换为弧度，从顶部开始
      startAngle -= Math.PI * 2 * easedProgress; // 动画效果：从0开始展开
      
      data.forEach((item, index) => {
        // 计算扇形角度
        const value = item.value || 0;
        const angle = (value / total) * Math.PI * 2 * easedProgress;
        const endAngle = startAngle + angle;
        
        // 获取颜色
        const color = item.itemStyle?.color || defaultColors[index % defaultColors.length];
        
        // 绘制扇形
        this._ctx.beginPath();
        // 移动到中心点
        this._ctx.moveTo(centerX, centerY);
        // 绘制外弧
        this._ctx.arc(centerX, centerY, outerRadius, startAngle, endAngle);
        // 如果是环形图，绘制内弧
        if (innerRadius > 0) {
          this._ctx.arc(centerX, centerY, innerRadius, endAngle, startAngle, true);
        } else {
          // 否则回到中心点
          this._ctx.lineTo(centerX, centerY);
        }
        // 闭合路径
        this._ctx.closePath();
        // 填充颜色
        this._ctx.fillStyle = color;
        this._ctx.fill();
        
        // 绘制扇形边框
        this._ctx.strokeStyle = '#ffffff';
        this._ctx.lineWidth = 2 * this._dpr;
        this._ctx.stroke();
        
        // 存储扇形数据用于交互
        this._pieData.push({
          startAngle,
          endAngle,
          value,
          name: item.name,
          color,
          centerX,
          centerY,
          innerRadius,
          outerRadius
        });
        
        // 更新起始角度
        startAngle = endAngle;
      });
      
      // 绘制标签（标签线和文字）
      if (pieSeries.label && pieSeries.label.show !== false && easedProgress > 0.8) {
        this._drawPieLabels(data, total, centerX, centerY, outerRadius, defaultColors);
      }
    }
    
    /**
     * 绘制饼图标签
     * @param {Array} data - 数据数组
     * @param {number} total - 总值
     * @param {number} centerX - 中心X坐标
     * @param {number} centerY - 中心Y坐标
     * @param {number} radius - 外半径
     * @param {Array} defaultColors - 默认颜色数组
     */
    _drawPieLabels(data, total, centerX, centerY, radius, defaultColors) {
      // 获取系列配置
      const series = this._option.series;
      const pieSeries = series.find(s => s.type === 'pie');
      
      // 标签配置
      const labelConfig = pieSeries.label || {};
      const labelLineConfig = pieSeries.labelLine || {};
      
      // 计算标签位置参数
      const labelRadius = radius + 15 * this._dpr; // 标签距离饼图的距离
      const lineLength = (labelLineConfig.length || 15) * this._dpr; // 引导线长度
      
      // 计算起始角度
      let startAngle = (pieSeries.startAngle || 90) * Math.PI / 180 - Math.PI / 2;
      
      // 设置文字样式
      this._ctx.font = `${11 * this._dpr}px sans-serif`;
      this._ctx.textBaseline = 'middle';
      
      // 遍历数据绘制标签
      data.forEach((item, index) => {
        const value = item.value || 0;
        if (value === 0) return;
        
        // 计算扇形角度
        const angle = (value / total) * Math.PI * 2;
        const endAngle = startAngle + angle;
        // 中间角度
        const midAngle = startAngle + angle / 2;
        
        // 获取颜色
        const color = item.itemStyle?.color || defaultColors[index % defaultColors.length];
        
        // 计算标签位置
        const cosMid = Math.cos(midAngle);
        const sinMid = Math.sin(midAngle);
        
        // 扇形边缘点
        const edgeX = centerX + radius * cosMid;
        const edgeY = centerY + radius * sinMid;
        
        // 标签线转折点
        const breakX = centerX + labelRadius * cosMid;
        const breakY = centerY + labelRadius * sinMid;
        
        // 标签文字位置
        const textX = breakX + (cosMid >= 0 ? lineLength : -lineLength);
        const textY = breakY;
        
        // 绘制引导线
        this._ctx.beginPath();
        this._ctx.moveTo(edgeX, edgeY);
        this._ctx.lineTo(breakX, breakY);
        this._ctx.lineTo(textX, textY);
        this._ctx.strokeStyle = color;
        this._ctx.lineWidth = 1 * this._dpr;
        this._ctx.stroke();
        
        // 绘制标签文字
        const textAlign = cosMid >= 0 ? 'left' : 'right';
        this._ctx.textAlign = textAlign;
        this._ctx.fillStyle = '#333333';
        
        // 格式化标签文字
        const percent = ((value / total) * 100).toFixed(1);
        const label = labelConfig.formatter 
          ? labelConfig.formatter.replace('{b}', item.name).replace('{c}', value).replace('{d}', percent)
          : `${item.name}: ${percent}%`;
        
        this._ctx.fillText(label, textX + (cosMid >= 0 ? 3 : -3) * this._dpr, textY);
        
        // 更新起始角度
        startAngle = endAngle;
      });
    }
    
    /**
     * 绘制饼图图例
     */
    _drawPieLegend() {
      // 获取图例配置
      const legend = this._option.legend;
      // 检查是否显示图例
      if (!legend || legend.show === false) return;
      
      // 获取系列数据
      const series = this._option.series;
      const pieSeries = series.find(s => s.type === 'pie');
      if (!pieSeries) return;
      
      // 获取数据
      const data = pieSeries.data || [];
      // 检查数据是否为空
      if (data.length === 0) return;
      
      // 默认颜色数组
      const defaultColors = ['#5470c6', '#91cc75', '#fac858', '#ee6666', '#73c0de', '#3ba272', '#fc8452', '#9a60b4', '#ea7ccc'];
      
      // 计算图例布局
      const legendData = data.map(item => item.name);
      const itemHeight = 20 * this._dpr;
      const itemWidth = 80 * this._dpr;
      const cols = 3; // 每行显示3个图例
      const rowSpacing = 10 * this._dpr;
      const colSpacing = 10 * this._dpr;
      
      // 计算图例起始位置（底部居中）
      const totalWidth = cols * itemWidth + (cols - 1) * colSpacing;
      const startX = (this._width * this._dpr - totalWidth) / 2;
      const startY = this._height * this._dpr - Math.ceil(legendData.length / cols) * (itemHeight + rowSpacing);
      
      // 设置文字样式
      this._ctx.font = `${11 * this._dpr}px sans-serif`;
      this._ctx.textAlign = 'left';
      this._ctx.textBaseline = 'middle';
      
      // 绘制每个图例项
      legendData.forEach((name, index) => {
        // 计算位置
        const row = Math.floor(index / cols);
        const col = index % cols;
        const x = startX + col * (itemWidth + colSpacing);
        const y = startY + row * (itemHeight + rowSpacing) + itemHeight / 2;
        
        // 获取对应颜色
        const color = data[index].itemStyle?.color || defaultColors[index % defaultColors.length];
        
        // 绘制色块
        this._ctx.beginPath();
        this._ctx.arc(x + 6 * this._dpr, y, 5 * this._dpr, 0, Math.PI * 2);
        this._ctx.fillStyle = color;
        this._ctx.fill();
        
        // 绘制文字（截断过长的名称）
        const maxTextWidth = itemWidth - 20 * this._dpr;
        let text = name;
        if (this._ctx.measureText(text).width > maxTextWidth) {
          // 截断文字
          while (this._ctx.measureText(text + '...').width > maxTextWidth && text.length > 0) {
            text = text.slice(0, -1);
          }
          text += '...';
        }
        this._ctx.fillStyle = '#666666';
        this._ctx.fillText(text, x + 16 * this._dpr, y);
      });
    }
    
    /**
     * 缓动函数 - easeOutCubic
     * 使动画开始快，结束时慢下来，更自然
     * @param {number} t - 输入进度（0-1）
     * @returns {number} 缓动后的进度（0-1）
     */
    _easeOutCubic(t) {
      // easeOutCubic 公式：1 - (1 - t)^3
      return 1 - Math.pow(1 - t, 3);
    }
  }

  // 导出 ECharts
  module.exports = echarts;

})(typeof window !== 'undefined' ? window : global);
